deleter() { local LC_ALL=C S="$1" D="$2" I="$3" P="${4:-8022}" L="$5" H="$6" TL="$7"; [ -z "$S" ] && echo "Using $(pwd)" || { echo "CD $S"; cd "$S" || return 1; }; { touch t1_$$ t2_$$ t3_$$ t4_$$; echo -e "\033[1;34m--- STEP 1: Slicing List ---\033[0m"; head -n "$H" "$L" | tail -n "$TL" | LC_ALL=C tr -d '\r' > t1_$$; local TOT=$(LC_ALL=C awk 'END {print NR}' t1_$$); local CNT=0 FOUND=0 LAST=0 NOW=0; echo -e "\033[1;34m--- STEP 2: Local Scan (Process ID $$) ---\033[0m"; printf "\r> Scanned: 0 / %d | Found: 0" "$TOT" >&2; while read -r f || [ -n "$f" ]; do [ -z "$f" ] && continue; if [ -f "$f" ]; then echo "$f"; ((FOUND++)); fi; ((CNT++)); NOW=${EPOCHREALTIME/./}; if ((CNT==1 || NOW-LAST>=30000)); then printf "\r> Scanned: %d / %d | Found: \033[1;33m%d\033[0m" "$CNT" "$TOT" "$FOUND" >&2; LAST=$NOW; fi; done < t1_$$ > t2_$$; printf "\r> Local Scan: \033[1;32mDONE\033[0m. Found \033[1;32m%d\033[0m existing files. \033[K\n" "$FOUND" >&2; echo -e "\033[1;34m--- STEP 3: Remote Scan ---\033[0m"; CNT=0; LAST=0; printf "\r> Found Remote: 0" >&2; cat t1_$$ | ssh -p "$P" "$I" "LC_ALL=C; cd \"$D\" && while read -r r || [ -n \"\$r\" ]; do [ -z \"\$r\" ] && continue; [ -f \"\$r\" ] && echo \"\$r\"; done" | while read -r f || [ -n "$f" ]; do [ -z "$f" ] && continue; echo "$f"; ((CNT++)); NOW=${EPOCHREALTIME/./}; if ((CNT==1 || NOW-LAST>=30000)); then printf "\r> Found Remote: \033[1;32m%d\033[0m" "$CNT" >&2; LAST=$NOW; fi; done > t3_$$; printf "\r> Remote Scan: \033[1;32mDONE\033[0m. Found \033[1;32m%d\033[0m matches. \033[K\n" "$CNT" >&2; LC_ALL=C grep -Fxf t3_$$ t2_$$ > t4_$$ || true; echo -e "\n\033[1;36m=== SUMMARY ===\033[0m\nRequested  : $TOT\nFound Here : $(wc -l < t2_$$)\nFound Remote: $(wc -l < t3_$$)\n\033[1;31mTO DELETE  : $(wc -l < t4_$$)\033[0m (Overlap)\n----------------\nFirst: $(head -n 1 t4_$$)\nLast : $(tail -n 1 t4_$$)\n"; read -p "Delete 'TO DELETE' files? (y/n) " c; [ "$c" = "y" ] && LC_ALL= xargs -d '\n' -a t4_$$ rm -v; rm t1_$$ t2_$$ t3_$$ t4_$$; }; }
